        parameters: {
            query?: never;
            header?: never;
            path?: never;
            cookie?: never;
        };
        get?: never;
        put?: never;
        /**
         * Withdraw funds from sub-account
         * @description Withdraws funds from a sub-account back to the associated wallet.
         *     Currency is automatically determined from sub-account's account_currency.
         *
         *     **Authentication**: x-api-key header required
         *
         *     **Access Control**: User must have access to the sub-account
         *
         *     **Important**: The withdrawal is executed in two critical steps:
         *     1. Funds are withdrawn from the external card service
         *     2. Funds are deposited to the wallet
         *
         *     If step 2 fails, a CRITICAL error is logged requiring manual reconciliation.
         *
         */
        post: {
            parameters: {
                query?: never;
                header?: never;
                path: {
                    /** @description The ID of the sub-account */
                    sub_account_id: string;
                };
                cookie?: never;
            };
            requestBody: {
                content: {
                    "application/json": {
                        /**
                         * @description Amount to withdraw.
                         * @example 100
                         */
                        amount: number;
                        /**
                         * Format: uuid
                         * @description Optional wallet UUID. If not provided, will use the wallet associated with the sub-account.
                         * @example 8205c701-cd41-4929-910f-fccbb949729a
                         */
                        wallet_id?: string;
                    };
                };
            };
            responses: {
                /** @description Withdrawal successful */
                200: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content: {
                        "application/json": {
                            /** @example true */
                            success?: boolean;
                            data?: {
                                /**
                                 * Format: uuid
                                 * @description Unique order identifier
                                 */
                                order_uuid?: string;
                                /**
                                 * @example COMPLETE
                                 * @enum {string}
                                 */
                                status?: "PENDING" | "COMPLETE" | "FAILED";
                                /** @description Amount withdrawn from sub-account */
                                amount_from?: number;
                                /** @description Amount deposited to wallet */
                                amount_to?: number;
                                /**
                                 * Format: uuid
                                 * @description Currency UUID
                                 */
                                to_uuid?: string;
                                meta?: {
                                    fee?: number;
                                    sub_account_id?: string;
                                    exchange_rate?: number;
                                };
                                /** Format: date-time */
                                created_at?: string;
                            };
                        };
                    };
                };
                /** @description Bad Request - One of the following:
                 *     - Missing required fields
                 *     - Invalid amount (must be positive number)
                 *     - Sub-account not found
                 *     - Card service withdrawal failed
                 *      */
                400: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content: {
                        "application/json": components["schemas"]["ApiErrorResponse"];
                    };
                };
                /** @description Forbidden - One of the following:
                 *     - Access denied to this sub-account
                 *     - Sub-account does not belong to the specified wallet
                 *     - Wallet not found
                 *      */
                403: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content: {
                        "application/json": components["schemas"]["ApiErrorResponse"];
                    };
                };
                /** @description Sub-account or wallet not found */
                404: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content: {
                        "application/json": components["schemas"]["ApiErrorResponse"];
                    };
                };
                /** @description Internal Server Error or CRITICAL ERROR
                 *
                 *     **CRITICAL**: If the card service withdrawal succeeded but deposit to wallet failed,
                 *     manual reconciliation is required. The error message will contain "CRITICAL" and the order_uuid.
                 *      */
                500: {
                    headers: {
                        [name: string]: unknown;
                    };
                    content: {
                        "application/json": components["schemas"]["ApiErrorResponse"];
                    };
                };
            };
        };
